INSERT INTO documents (id, content_sha256, source, external_id, url, title, raw_text, retrieved_at, meta) VALUES ('e02a6ae1-d777-49c6-afa2-305aab5b7f63', '9465c6364865cbfc5a740e596f5143d5dd69677292b5fa19568ac67cc3bbd5f5', 'pubmed', '10334745', 'https://pubmed.ncbi.nlm.nih.gov/10334745/', 'Efficacy of vitamin B-6 in the treatment of premenstrual syndrome: systematic review.', 'Efficacy of vitamin B-6 in the treatment of premenstrual syndrome: systematic review.
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('e0efbd4c-972c-49e8-ae0e-c36e92811440', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 0, 141, 'The impact of essential fatty acid, B vitamins, vitamin C, magnesium and zinc supplementation on stress levels in women: a systematic review.', 'a59da55633104c65fbaf371ba3fc4ae91709d447f3f595ba47d78f058f018a65', 0, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('c9965b34-eff3-48a2-885d-f15c4bd218e3', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 143, 259, 'BACKGROUND: Women juggling multiple roles in our complex society are increasingly experiencing psychological stress.', '0c6426f503b961cac048929e3da9eb0765a9e5f82d2a8ba7a399548a68c34db4', 1, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('f8ff81bc-7710-4ded-9caf-137d80e9bf80', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 260, 351, 'Dietary supplementation to manage stress is widespread despite limited supporting evidence.', '918754ca221b637ee74225a3af13ca51bc1b9b5cc3bd84d263b6dceb6b745096', 2, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('2ce4b0d8-628a-4805-8df4-040ae9724052', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 352, 513, 'A systematic review of the available literature was undertaken to investigate the efficacy of specific dietary supplements in managing female stress and anxiety.', '7b2f7ee60dad03e94f0b219371dc927cdbb241b7c0727b2781d6df513d8ebb9b', 3, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('c944817f-bd01-4714-840a-19c0635c864e', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 514, 715, 'OBJECTIVES: To identify the impact of essential fatty acids (EFAs), B vitamins, vitamin C, magnesium and/or zinc, consumed as dietary supplements to the daily diet, on female stress and anxiety levels.', 'eae9366323c2780394f62edcd6af5590bf0ad311effe7a2b57e07fa8d3948687', 4, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('9aadf6aa-2930-4cfb-b039-32742ada967c', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 716, 862, 'INCLUSION CRITERIA TYPES OF PARTICIPANTS: Women aged 18 years and over, who had participated in a study where stress and/or anxiety were assessed.', 'a062ad7853d1cacabcb023a73be0c5ad03d2d59e7254de9f5828c5a619736739', 5, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('cfc522d8-fdf3-4b21-8836-7fce9ef4f9de', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 863, 969, 'TYPES OF INTERVENTION(S): Dietary supplementation with EFAs, B vitamins, vitamin C, magnesium and/or zinc.', '4b7b5844444fddb1e5a32075b3937fe6894ee695996da93261a24265f6d0f934', 6, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('e77bc508-7a71-4fd8-8747-4f434225c4e1', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 970, 1084, 'TYPES OF COMPARATORS: Supplements, either alone or combined, were compared with either no intervention or placebo.', '982547217db89e95863752dd163c60e8f943405a485fd6f5db0831b7c503aca8', 7, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('bdd84cb1-e4db-4240-bc0f-2d026d2f2ddc', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 1085, 1168, 'TYPES OF STUDIES: Randomized controlled and pseudo-randomized trials were included.', '4f2a767e96f23621c86cbae1b58ced1c3f8618e89e76550bbb102f488dcbd110', 8, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('0b30a470-2614-4bb5-baf8-37275bcbb9dc', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 1169, 1264, 'OUTCOMES: Stress and anxiety were assessed using self-report or physiological outcome measures.', 'ac75d1a1af5de88e42bc69afb157e6e27137ff9b5368239de9f6e32aa65662c6', 9, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('7cd0c969-29bc-4a4d-8f72-8a6eb560bd0d', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 1265, 1506, 'SEARCH STRATEGY: Published and unpublished studies were sought via MEDLINE (via PubMed), Embase, Scopus, CINAHL, PsycINFO, PsycARTICLES, MedNar, National Institute of Mental Health and the International Association for Women''s Mental Health.', 'ae68461cad1739aa9df661a11ec2dc25fe2179a95c633bd9c24bed379142d828', 10, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('ced82495-e094-49f8-b548-9e90af86d72f', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 1507, 1651, 'METHODOLOGICAL QUALITY: Methodological quality was evaluated using standardized critical appraisal instruments from the Joanna Briggs Institute.', '98e7456470d3b6b96f9afb6a012a1dcc8173db0483dcd935ce2ef81a17b47f55', 11, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('f2be19a2-69b3-416b-9d56-901f7c7b7270', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 1652, 1773, 'DATA EXTRACTION: Data were extracted using the standardized data extraction instruments from the Joanna Briggs Institute.', '8e23aa25c99bea7f9d8882ea878cf5fc3ac2c703c2a4ffbef4713b65a1705512', 12, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('a88ed979-c5b8-4efd-910d-99e0b53d3ef1', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 1774, 1870, 'DATA SYNTHESIS: Due to heterogeneity of the included studies, narrative synthesis was performed.', '7f9a91f53dfe7a75a815d78ca98be40f59545557f94835a7d0ddeaaf915370f7', 13, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('99653319-09c2-4653-bd7c-6e77ab971bd2', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 1871, 1926, 'RESULTS: Fourteen studies were included in this review.', 'ad2cf712ccab3fb25a0f490eaa221af01166a141c0241a518b07698658632ba3', 14, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('43bf5e4d-0f2d-4ab6-a4cb-d88e396a0e2a', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 1927, 2186, 'Essential fatty acids were effective in reducing perceived stress and salivary cortisol levels during pregnancy and anxiety in premenstrual women, and anxiety during menopause in the absence of depression, but were ineffective when depression was disregarded.', '1e03a09c216fa4a73b7356f79d1c141a6cd18d83d762e4b1de17c0d3e43aea52', 15, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('0b403644-189a-4d37-908c-a63678aee57f', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 2187, 2296, 'Disregarding the hormonal phase, EFAs were ineffective in reducing stress or anxiety in four groups of women.', '2acb587335218d4b5b3f52842a21c05ea0737b5f07d272f3b35fe142b499978b', 16, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('cc46d677-4bc7-4f74-ac2b-3db479d9d311', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 2297, 2515, 'Combined magnesium and vitamin B6 supplementation reduced premenstrual anxiety but had no effect when used in isolation and did not affect stress in women suffering from dysmenorrhea when combined or used in isolation.', '1d04bae357b08d5a18313c54ddeaf60d2439f0c1a3aa97d99b6e7c8b6e90fa6c', 17, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('a4b9436b-1e0b-4190-a14a-877b16067dbb', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 2516, 2606, 'Older women experienced anxiety reduction using vitamin B6, but not folate or vitamin B12.', 'de2c0aae2cadbc81518b1c0b4812f8deacb788678e7e65b1c1b443f04fffac01', 18, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('8eac5f6d-7ef7-4355-997b-5e9d19da4272', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 2607, 2720, 'High-dose sustained-release vitamin C was effective in reducing anxiety and blood pressure in response to stress.', '7433f1bd2cca675e037c725eac05033b87e4fa608479a2edec1092898796d4d1', 19, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('24d027a0-7c96-4842-9f66-6e9e7e533e9c', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 2721, 2940, 'CONCLUSION: The current review suggests that EFAs may be effective in reducing prenatal stress and salivary cortisol and may reduce anxiety during premenstrual syndrome and during menopause in the absence of depression.', '1003eb64b3c4bf7e009d9c8105fa4e9dccf7d92ccb72ab4f736c0a88dcce0753', 20, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('a35ca13c-48bb-4145-954a-1fdc05652e6e', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 2941, 3098, 'Magnesium and vitamin B6 may be effective in combination in reducing premenstrual stress, and vitamin B6 alone may reduce anxiety effectively in older women.', 'd2df4463a1c6201363aff0842cac666b84d9bb7dfadd892b71e1524fa4e59f9e', 21, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('27d143f7-b7ae-4f5f-9e4d-1992f5f85628', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 3099, 3216, 'High-dose sustained-release vitamin C may reduce anxiety and mitigate increased blood pressure in response to stress.', '422000739958064ef0be04e1f9a4ab89f60db188430afed41b11cc3e78d6b37e', 22, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('040e42e6-75cd-418c-805e-f91d983bb87b', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 3217, 3409, 'IMPLICATIONS FOR PRACTICE: Essential fatty acids may be effective in reducing prenatal stress and salivary cortisol levels, and premenstrual or menopausal anxiety in the absence of depression.', 'd11e3be307b1543ddc6a5ab543e1e3c1d5cf6e609179027e187e1e0f4cade6eb', 23, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('5ec1b4a6-99e8-499f-bcc5-79610b5d4147', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 3410, 3526, 'Combining magnesium and vitamin B6 may reduce premenstrual anxiety and vitamin B6 may reduce anxiety in older women.', '22af4dc2db6fc6ce840369340ce4f6976bf98b345f5d7e1a65ce973f992e2b3e', 24, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('3487c5ee-0605-4438-a3fa-c5928cdec395', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 3527, 3644, 'High-dose sustained-release vitamin C may reduce anxiety and mitigate increased blood pressure in response to stress.', '422000739958064ef0be04e1f9a4ab89f60db188430afed41b11cc3e78d6b37e', 25, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('3f3b6717-cd42-4ee4-9508-77adc99951cd', '89232a08-3733-41d5-bb81-7d80dd14d4d6', 3645, 3847, 'IMPLICATIONS FOR RESEARCH: Investigating supplementation in longer term studies is warranted and should include compliance testing, the use of inert substances as controls and reliable outcome measures.', '84aa00516637d0e25c10bd63adf42afdd52f8be8fd56a1a6d1d8470cc0741a94', 26, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('4a53f213-3088-40f2-a8a4-2eee1ea56213', '6e79669d-8252-4742-93f2-4496a8ae52c8', 0, 102, 'Vitex agnus-castus extracts for female reproductive disorders: a systematic review of clinical trials.', '3e654892fc46c9cdd002b825d03082a1e482398ff232b0b4a2b1a26fbdc7ba9d', 0, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('eedc251b-b9fe-4f6f-ae40-0d3b3d8798fb', '6e79669d-8252-4742-93f2-4496a8ae52c8', 104, 125, 'Vitex agnus-castus L.', 'c2f2fb376f67816fe729576eaf3f76ceb11ab63aefc58650ee491229ca9b288f', 1, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('dad82840-9943-4f73-a51c-260ea777e3bd', '6e79669d-8252-4742-93f2-4496a8ae52c8', 126, 289, '(chaste tree; chasteberry) is a popular herbal treatment, predominantly used for a range of female reproductive conditions in Anglo-American and European practice.', '6613aaa492c756b8716ceab3bbd39f8dbab17c31f553e0be15f984eb03661c6a', 2, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('6a9d13f1-4671-42c0-bfcf-3f0ca7c10779', '6e79669d-8252-4742-93f2-4496a8ae52c8', 290, 676, 'The objective of this systematic review was to evaluate the evidence for the efficacy and safety of Vitex extracts from randomised, controlled trials investigating women''s health.Eight databases were searched using Latin and common names for Vitex and phytotherapeutic preparations of the herb as a sole agent, together with filters for randomised, controlled trials or clinical trials.', 'f1c6e5dfdbd7ff72258b6f50e2b9f720f057dd75918916900605524a3371e426', 3, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('86bc3543-9f42-435f-bbe8-ea8347405e0d', '6e79669d-8252-4742-93f2-4496a8ae52c8', 677, 1080, 'Methodological quality was assessed according to the Cochrane risk of bias and Jadad scales, as well as the proposed elaboration of CONSORT for reporting trials on herbal interventions.Thirteen randomised, controlled trials were identified and twelve are included in this review, of which eight investigated premenstrual syndrome, two premenstrual dysphoric disorder, and two latent hyperprolactinaemia.', '8aefa7379447de883501a543e6fcb0b37ddf04e8683dbeb038c2e251469849ee', 4, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('37a835f7-62fd-4fee-8be6-be985ab3239b', '6e79669d-8252-4742-93f2-4496a8ae52c8', 1081, 1235, 'For premenstrual syndrome, seven of eight trials found Vitex extracts to be superior to placebo (5 of 6 studies), pyridoxine (1), and magnesium oxide (1).', '316f5cd15613b17c537a0933a8daf6b39f7efe7b506f9d08d212001944d5471f', 5, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('b50bc7d3-fb42-462d-ad99-c6ead8a49cbb', '6e79669d-8252-4742-93f2-4496a8ae52c8', 1236, 1379, 'In premenstrual dysphoric disorder, one study reported Vitex to be equivalent to fluoxetine, while in the other, fluoxetine outperformed Vitex.', '38a4aa5e4ac16105ea09c248e4f6436491c4558bdf316a462925819ac9c3d534', 6, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('4f24c3e6-b4ef-4782-bff0-d807c96dab1c', '6e79669d-8252-4742-93f2-4496a8ae52c8', 1380, 1734, 'In latent hyperprolactinaemia, one trial reported it to be superior to placebo for reducing TRH-stimulated prolactin secretion, normalising a shortened luteal phase, increasing mid-luteal progesterone and 17β-oestradiol levels, while the other found Vitex comparable to bromocriptine for reducing serum prolactin levels and ameliorating cyclic mastalgia.', '26e084b895e488c7f8742eaf270baa09df1fa5deb5eb9795e12738614b8d68e1', 7, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('c716c092-f819-4715-9562-23961836d6fb', '6e79669d-8252-4742-93f2-4496a8ae52c8', 1735, 1796, 'Adverse events with Vitex were mild and generally infrequent.', 'a0b45d5d1ee548c9a7401b0764ee6ce633ec97672d13e3ebdf93f5cf46d6586d', 8, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('12244c92-891d-49b3-9673-d15a1287dad6', '6e79669d-8252-4742-93f2-4496a8ae52c8', 1797, 1891, 'The methodological quality of the included studies varied, but was generally moderate-to-high.', 'b6a738cb0d6cf55d384ad9ebcd3bb528a9c44cf9f7b9ec3d89fc4ebc1cf2c4f4', 9, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('8171391f-ac26-411b-83bf-03c2db9a8882', '6e79669d-8252-4742-93f2-4496a8ae52c8', 1892, 2265, 'Limitations include small sample sizes in some studies, heterogeneity of conditions being treated, and a range of reference treatments.Despite some methodological limitations, the results from randomised, controlled trials to date suggest benefits for Vitex extracts in the treatment of premenstrual syndrome, premenstrual dysphoric disorder and latent hyperprolactinaemia.', 'fac4749d9727b453689743e90b3cc2988604dd70488cc92c6def27e3a5e6bfb0', 10, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('77a60c32-9b19-4344-b935-ebb1299ad33d', '6e79669d-8252-4742-93f2-4496a8ae52c8', 2266, 2355, 'Further research is recommended, and greater transparency in reporting for future trials.', '6cd959464fe06db7fa922a4217114a0220bf6cad6fd087f726b7d96208bfd48e', 11, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('3cc69d47-9f9c-4587-a2b7-c99945d46ee6', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 0, 22, 'Premenstrual syndrome.', 'b7e790e52ece05a9e87dd6bfd33330c6caea413c9c4de327b74d79bde32b39b4', 0, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('ccd37bfa-d21c-448b-8430-c271a8eadb9c', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 24, 102, 'INTRODUCTION: Premenstrual symptoms occur in 95% of women of reproductive age.', '996c5824d82d7a68b578b5f58f957065e9a2860453e790595dd38c84bac6c9dd', 1, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('19add161-04cb-4f15-97e4-46069f016708', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 103, 172, 'Severe, debilitating symptoms (PMS) occur in about 5% of those women.', 'd55fada5476a30515fcd6f172404914a3ff0bac0331903a63130188e96ab26bb', 2, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('b87a47c9-4bed-426b-a401-84d00ceaa3a5', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 173, 352, 'There is no consensus on how symptom severity should be assessed, which has led to a wide variety of symptoms scales, making it difficult to synthesise data on treatment efficacy.', '4cde4a3244dbf58c86a386ec89299c1e46d4811fd57ce06a0be358b67b9ac848', 3, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('bdcdcf80-7834-4c2e-b614-5114e8c822b7', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 353, 430, 'The cyclical nature of the condition also makes it difficult to conduct RCTs.', 'b2d2b22d02088b136fc6aa6f7196a5cbfff254ec5626c35624abb2834f57d79f', 4, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('47ae503f-01d4-4599-9a42-3dd49a59a4e0', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 431, 732, 'METHODS AND OUTCOMES: We conducted a systematic review and aimed to answer the following clinical questions: What are the effects of drug treatments; hormonal treatments; psychological interventions; physical therapies; dietary supplements; and surgical treatments in women with premenstrual syndrome?', '2613c35342c99c750704de536755dcca377b2e5e76cd39d5331783f4322255a7', 5, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('36c9ac57-6854-4f1f-80e6-11710f95a9f1', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 733, 960, 'We searched: Medline, Embase, The Cochrane Library and other important databases up to November 2006 (Clinical Evidence reviews are updated periodically, please check our website for the most up-to-date version of this review).', '268450b404c066bd66b7970cd8fa50e0340d7fcaca15e24f8e01f1c3bdd04682', 6, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('be65e875-f696-469b-b31a-88461acc4c64', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 961, 1134, 'We included harms alerts from relevant organisations such as the US Food and Drug Administration (FDA) and the UK Medicines and Healthcare products Regulatory Agency (MHRA).', 'b4aec9ed548b11987b45b01f8e624b72303d2cac245eb03d5e5c257b932a9957', 7, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('b2c4fb88-0195-413c-8039-a7e1b53303ef', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 1135, 1239, 'RESULTS: We found 52 systematic reviews, RCTs, or observational studies that met our inclusion criteria.', 'b67e526df4bae684a84afdc82164feea757b226419edb0d55eab147b9cd5421c', 8, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('f9b25bbd-80ce-4f1a-ab46-6ed170f6e5fc', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 1240, 1317, 'We performed a GRADE evaluation of the quality of evidence for interventions.', 'd6774a3109bdd1604f869773916d89522b7c586bccff6f3df5b80b1d90a7c851', 9, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('ffc09cd7-caf2-466b-82a3-92b5f8c3355c', 'a4c6bdad-8758-4c37-9e9d-35ebf559653f', 1318, 1958, 'CONCLUSIONS: In this systematic review we present information relating to the effectiveness and safety of the following interventions: acupuncture, alprazolam, bright light therapy, buspirone, chiropractic manipulation, clomipramine, cognitive behavioural therapy, danazol, endometrial ablation, evening primrose oil, exercise, gonadorelin analogues, hysterectomy, laparoscopic bilateral oophorectomy, magnesium supplements, metolazone, non-steroidal anti-inflammatory drugs, oestrogens, oral contraceptives, progesterone, progestogens, pyridoxine, reflexology, relaxation, selective serotonin reuptake inhibitors, spironolactone, tibolone.', '8afdc4f3d5fc00016a1b2029aee14431fef8758967d201bc9c73b169b7878559', 10, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('b3f8171f-43a1-4a6a-bf48-c0e126173880', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 0, 85, 'Efficacy of vitamin B-6 in the treatment of premenstrual syndrome: systematic review.', '65e504b1b01df7fc761b493a4bd524c430b806c6dd5f46c1cd8befc8429f09ea', 0, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('383254bc-9e0a-41ef-97d3-1d34950dbc45', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 87, 180, 'OBJECTIVE: To evaluate the efficacy of vitamin B-6 in the treatment of premenstrual syndrome.', 'ba35c88d1631073760ba8342c5e6a668b1fc6653c0a794a171e68a716644a02d', 1, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('fa74c7e3-f4f0-4d42-918b-7ef64d69541b', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 181, 352, 'DESIGN: Systematic review of published and unpublished randomised placebo controlled trials of the effectiveness of vitamin B-6 in the management of premenstrual syndrome.', 'cd02f2709f27c74215eddddd216023a44e17cb3087af5bbb894036bcfc39c47b', 2, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('6c2d3860-966e-47ac-b474-2c769a84ad5a', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 353, 438, 'SUBJECTS: Nine published trials representing 940 patients with premenstrual syndrome.', '59651e3b7a451df1dbeecd3f7e5f6d72673ead0c487baa64ff478d7d03eb9e5c', 3, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('c1f9e489-285e-4ce0-84d8-a937107ad4da', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 439, 553, 'MAIN OUTCOME MEASURES: Proportion of women whose overall premenstrual symptoms showed an improvement over placebo.', '03261bbc3a39381125bc9c645d7cb51958540839f5b6b5d31394002b13089676', 4, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('970bda63-0d4b-4ec6-b236-4b61939616d4', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 554, 690, 'A secondary analysis was performed on the proportion of women whose premenstrual depressive symptoms showed an improvement over placebo.', '90ff13fda6da59fef015438186b89e983a29e40e90324fbf843c3cfe19da4c7c', 5, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('a973ea51-a2c3-40e6-a636-0f751ccceb37', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 691, 831, 'RESULTS: Odds ratio relative to placebo for an improvement in overall premenstrual symptoms was 2.32 (95% confidence interval 1.95 to 2.54).', '7bb209dc1dedf2dfeb7d65301aadab75ed7b9280968a934973215b482a56c19f', 6, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('3016b342-b380-46a0-9172-9a2b6ebb5a68', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 832, 972, 'Odds ratio relative to placebo for an improvement in depressive symptoms was 1.69 (1.39 to 2.06) from four trials representing 541 patients.', 'fafe900182d0b2c65e807ed615676c9ba9f3ec5ae8b5d509a2bce04c6eb3da7a', 7, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('b87202b6-6c41-4072-a270-a232a08c8b9f', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 973, 1059, 'CONCLUSION: Conclusions are limited by the low quality of most of the trials included.', 'dbe80d118082f72ff0675935982d053cce6c4ac9d6d088775d2a2b33524f7c67', 8, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO source_spans (id, document_id, start_char, end_char, text, sha256, ordinal, extracted) VALUES ('ff981250-2f3a-485c-9b38-a8d128451659', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 1060, 1209, 'Results suggest that doses of vitamin B-6 up to 100 mg/day are likely to be of benefit in treating premenstrual symptoms and premenstrual depression.', 'a93566ec49d51226676300b9d24dd430b538458a312d1f91ef70e33548bec22b', 9, true) ON CONFLICT (id) DO NOTHING;
