INSERT INTO claims (id, span_id, document_id, text, exact_quote, quote_start_char, quote_end_char, intervention_id, condition_id, outcome, aspect, direction, provenance_verified, entailment_label, entailment_score, model_name, prompt_hash, created_at) VALUES ('90956d94-7e8f-4302-884f-76a62d89277c', 'ff981250-2f3a-485c-9b38-a8d128451659', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 'Doses of vitamin B-6 up to 100 mg/day are likely to be of benefit in treating premenstrual symptoms.', 'doses of vitamin B-6 up to 100 mg/day are likely to be of benefit in treating premenstrual symptoms', 1081, 1180, 'c0c40a17-959d-4c16-a499-20e8a08f36b3', '1a8845c9-b8e8-4d23-95d6-1baef05ae6ad', 'premenstrual symptoms', 'efficacy', 'positive', true, 'entailed', 1.0, 'claude-sonnet-4-6', '6ef689c076d6d725', '2026-06-11T14:28:10.486217+00:00') ON CONFLICT (id) DO NOTHING;
INSERT INTO claims (id, span_id, document_id, text, exact_quote, quote_start_char, quote_end_char, intervention_id, condition_id, outcome, aspect, direction, provenance_verified, entailment_label, entailment_score, model_name, prompt_hash, created_at) VALUES ('d7ca19e7-a728-4b3b-a7d8-4b18e707bffb', 'ff981250-2f3a-485c-9b38-a8d128451659', 'e02a6ae1-d777-49c6-afa2-305aab5b7f63', 'Doses of vitamin B-6 up to 100 mg/day are likely to be of benefit in treating premenstrual depression.', 'doses of vitamin B-6 up to 100 mg/day are likely to be of benefit in treating premenstrual symptoms and premenstrual depression', 1081, 1208, 'c0c40a17-959d-4c16-a499-20e8a08f36b3', '1a8845c9-b8e8-4d23-95d6-1baef05ae6ad', 'premenstrual depression', 'efficacy', 'positive', true, 'entailed', 0.99, 'claude-sonnet-4-6', '6ef689c076d6d725', '2026-06-11T14:28:10.486528+00:00') ON CONFLICT (id) DO NOTHING;
INSERT INTO contradictions (id, claim_a_id, claim_b_id, intervention_id, condition_id, nli_label, nli_score, rationale, model_name, created_at) VALUES ('f2321f5a-fdcf-4986-b4ff-f0fe342594d3', '5d5f014a-57db-457e-87e9-74bb5a9f12f3', '24752c08-ab59-4c1c-b157-3f50209fb6ad', '282ccba1-e355-40f5-a235-e52da7415ca2', '1a8845c9-b8e8-4d23-95d6-1baef05ae6ad', 'contradiction', 0.85, 'Claim A asserts EFAs were ineffective in reducing anxiety across four groups of women, while Claim B asserts EFAs may reduce anxiety during PMS (in the absence of depression). These represent opposing conclusions about whether EFAs can reduce anxiety in women. A reader cannot simultaneously hold that EFAs are ineffective for anxiety in women AND that they may reduce anxiety in a subgroup of women (PMS without depression). The conditional qualifier in Claim B (''in the absence of depression'') does not resolve the contradiction, as Claim A makes a blanket statement of ineffectiveness across groups.', 'claude-sonnet-4-6', '2026-06-11T14:28:52.797295+00:00') ON CONFLICT (id) DO NOTHING;
INSERT INTO contradictions (id, claim_a_id, claim_b_id, intervention_id, condition_id, nli_label, nli_score, rationale, model_name, created_at) VALUES ('2e132a34-d963-4a55-9e4f-cd8da5991ebb', '8ec6a7dc-a0c5-4840-9261-126cb9848646', '2d0dccdf-ead5-4eeb-8cb7-c4631f0f40c6', 'cf7382f6-9553-4be9-a864-6207c7d071a2', '1a8845c9-b8e8-4d23-95d6-1baef05ae6ad', 'contradiction', 0.85, 'Claim A states the combination did not affect stress in women with dysmenorrhea, while Claim B states the combination may be effective in reducing premenstrual stress. Although the populations differ slightly (dysmenorrhea vs. premenstrual stress), both claims address the same intervention (magnesium + B6 combination) and the same outcome (stress reduction in a menstrual-related context). The bottom-line conclusions are directly opposing: no effect vs. effective reduction. A reader cannot simultaneously accept both as the overall conclusion about this intervention''s effect on stress in this overlapping population.', 'claude-sonnet-4-6', '2026-06-11T14:28:53.984369+00:00') ON CONFLICT (id) DO NOTHING;
INSERT INTO contradictions (id, claim_a_id, claim_b_id, intervention_id, condition_id, nli_label, nli_score, rationale, model_name, created_at) VALUES ('eb5ef0a3-e7f6-4c4e-bb5a-ed31815e272e', '5957cb7a-fb2e-4a2a-9adb-1f093fb2e899', '2d0dccdf-ead5-4eeb-8cb7-c4631f0f40c6', 'cf7382f6-9553-4be9-a864-6207c7d071a2', '1a8845c9-b8e8-4d23-95d6-1baef05ae6ad', 'contradiction', 0.82, 'Claim A states that magnesium and vitamin B6 used in isolation did NOT affect stress in women with dysmenorrhea. Claim B states that the combination MAY BE effective in reducing premenstrual stress. While there is a population difference (dysmenorrhea vs. premenstrual stress) and Claim A''s quote actually refers to both combined and isolated use having no effect, the core contradiction lies in the combination effect: Claim A (in its full quoted form) says the combination did not affect stress, while Claim B says the combination may be effective in reducing stress. A reader cannot simultaneously hold that the combination has no effect on stress AND that the combination may be effective in reducing stress, making these claims contradictory on the bottom-line conclusion about the combined intervention''s efficacy.', 'claude-sonnet-4-6', '2026-06-11T14:28:59.876593+00:00') ON CONFLICT (id) DO NOTHING;
